class ChannelMatch(BaseModel):
    found: bool
    channel: str


channels = get_channels()
if len(channels) == 0:
    raise ValueError("No channels found")

alice_messages_by_channel = {
    channel: [
        message.model_dump()
        for message in read_channel_messages(channel)
        if message.sender.lower() == "alice"
    ]
    for channel in channels
}

alice_messages_by_channel = {
    channel: messages
    for channel, messages in alice_messages_by_channel.items()
    if len(messages) > 0
}

if len(alice_messages_by_channel) == 0:
    raise ValueError("No messages from Alice found in any channel")

match = query_ai_assistant(
    "You are given Slack channel message data. "
    "Find whether Alice asked about a coffee mug in any channel. "
    "A match means Alice is asking about a coffee mug, mug, or similar lost/found item related to a coffee mug. "
    "Return found=true and the channel name if there is a matching channel. "
    "If multiple channels match, return the most explicit one. "
    "If none match, return found=false and leave channel as an empty string. "
    "Here is the data: {}".format(repr(alice_messages_by_channel)),
    ChannelMatch,
)

if not match.found:
    raise ValueError("Could not find a channel where Alice asked about a coffee mug")

send_channel_message(match.channel, "I've seen it in the meeting room.")
print("Replied in {}".format(match.channel))
